@startuml
!theme plain

class "Metric" as Metric {
  +resultCompare()
  +sendNotification()
}

class "DataSet" as DataSet {
  +value
  +date
  +dataSetType
  +getValue()
  +getDate()
  +getDataSetType()
  +return date to compare and info about metric type
}

class "ResultCompare" as ResultCompare {
  +currentValue
  +previousValue
  +dataSetType
  +CmpMethods()
  +return (-1;0;1)
}

class "Notification" as Notification {
  +sendTo
  +message
  +sendMethod()
  +return send message
}

class "SendMethod" as SendMethod {
  +sendMethod()
  +return send method
}

class "CmpMethods" as CmpMethods {
  +cmpMethod()
  +return select method
}

Metric --|> ResultCompare
Metric --|> Notification
ResultCompare <|-- CmpMethods
Notification --> SendMethod
ResultCompare --> DataSet

@enduml
